return [{ json: { ok: true, sent: 'welcome' } }];

const incoming = $input.first().json;
const user_id    = incoming.user_id ?? '';
const reply_token = incoming.reply_token ?? '';
const text       = incoming.text ?? '';

const DIFY_KEY   = $vars.DIFY_API_KEY || process.env.DIFY_API_KEY || '';
const DIFY_URL   = $vars.DIFY_API_URL || process.env.DIFY_API_URL || 'http://nginx/v1';
const BRIDGE_URL = $vars.BRIDGE_INTERNAL_URL || process.env.BRIDGE_INTERNAL_URL || 'http://hospital-bridge:8000';
const BRIDGE_TOK = $vars.BRIDGE_INTERNAL_TOKEN || process.env.BRIDGE_INTERNAL_TOKEN || '';
const SESSION_URL = `${BRIDGE_URL}/internal/session/line_main/${encodeURIComponent(user_id)}`;
const MESSAGE_URL = `${BRIDGE_URL}/internal/message`;
const AUTH_HDR   = { 'X-Internal-Token': BRIDGE_TOK, 'Content-Type': 'application/json' };

// Layer 1: explicit human-request keywords (from AI takeover research).
// If any of these appear the patient wants a human — skip Dify entirely.
const HUMAN_REQ_KEYWORDS = [
  'คุยกับคน', 'คุยกับเจ้าหน้าที่', 'อยากคุยกับคน',
  'ขอเจ้าหน้าที่', 'ขอพนักงาน', 'ขอคุยกับคน',
  'ต้องการคุยกับเจ้าหน้าที่', 'ให้คนตอบ', 'ไม่อยากคุยกับ bot',
  'ไม่อยากคุยกับบอท', 'ขอแอดมิน', 'talk to human',
  'speak to agent', 'human please'
];
const lowerText = String(text).toLowerCase();
const hasHumanReq = HUMAN_REQ_KEYWORDS.some(k => lowerText.includes(k.toLowerCase()));

const httpRequest = this.helpers.httpRequest.bind(this.helpers);
async function fetch(url, options = {}) {
  const headers = options.headers ?? {};
  const method = options.method ?? 'GET';
  const contentType = String(headers['Content-Type'] ?? headers['content-type'] ?? '');
  let body = options.body;
  const req = { method, url, headers, simple: false, returnFullResponse: true, resolveWithFullResponse: true };
  if (body !== undefined) {
    if (typeof body === 'string' && contentType.includes('application/json')) {
      req.body = body; req.json = false;
    } else { req.body = body; }
  }
  const res = await httpRequest(req);
  const status = res.statusCode ?? res.status ?? 200;
  const rb = res.body ?? res;
  return {
    ok: status >= 200 && status < 300, status,
    json: async () => typeof rb === 'string' ? JSON.parse(rb || '{}') : rb,
    text: async () => typeof rb === 'string' ? rb : JSON.stringify(rb)
  };
}
async function getLineToken(id, sec) {
  const r = await fetch('https://api.line.me/v2/oauth/accessToken', {
    method: 'POST', headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: `grant_type=client_credentials&client_id=${encodeURIComponent(id)}&client_secret=${encodeURIComponent(sec)}`
  });
  return (await r.json()).access_token;
}async function pushCroAlert(bodyText) {
  try {
    const croUserRes = await fetch(`${BRIDGE_URL}/internal/booking/cro-user/latest`, { headers: AUTH_HDR });
    const cro_uid = croUserRes.ok ? (await croUserRes.json()).user_id : null;
    if (!cro_uid) return;
    const croTok = await getLineToken(
      $vars.LINE_CRO_CHANNEL_ID || process.env.LINE_CRO_CHANNEL_ID || '',
      $vars.LINE_CRO_CHANNEL_SECRET || process.env.LINE_CRO_CHANNEL_SECRET || ''
    );
    await fetch('https://api.line.me/v2/bot/message/push', {
      method: 'POST',
      headers: { Authorization: `Bearer ${croTok}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ to: cro_uid, messages: [{ type: 'text', text: bodyText.slice(0, 4900) }] })
    });
  } catch(e) { console.error('CRO alert push error:', String(e?.message ?? e)); }
}

// 1. get session + effective mode
let conv_id = '';
let effective_mode = 'auto';
let sticky_mode = 'auto';
let banner = 'auto';
try {
  const sr = await fetch(SESSION_URL, { headers: AUTH_HDR });
  if (sr.ok) {
    const sess = await sr.json();
    conv_id = sess.dify_conversation_id ?? '';
    effective_mode = sess.effective_mode ?? 'auto';
    sticky_mode = sess.sticky_mode ?? 'auto';
    banner = sess.banner ?? 'auto';
  }
} catch (e) { console.error('get session error:', String(e?.message ?? e)); }

// Layer 1 keyword overrides mode: forces silent handoff to CRO.
if (hasHumanReq && effective_mode !== 'silent') {
  effective_mode = 'silent';
  banner = 'keyword_handoff';
}

// SILENT branch: skip Dify, push CRO alert, don't reply patient.
if (effective_mode === 'silent') {
  const alertText = `[ลูกค้าถามระหว่าง AI ปิด] ผู้ใช้ ${user_id}\nข้อความ: ${text}\n\nโหมด: ${banner} sticky: ${sticky_mode}\nกรุณาเปิด BBH Portal เพื่อตอบกลับ`;
  await pushCroAlert(alertText);
  return [{ json: { ok: true, user_id, mode: 'silent', skipped_dify: true } }];
}

// 2. ask Dify (auto + copilot branches)
let answer = 'ขออภัยค่ะ ระบบไม่พร้อมให้บริการในขณะนี้ กรุณาลองใหม่ภายหลังค่ะ';
let route_prefix = null;
let new_conv_id = conv_id;
try {
  const difyRes = await fetch(`${DIFY_URL}/chat-messages`, {
    method: 'POST',
    headers: { Authorization: `Bearer ${DIFY_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ inputs: { role: 'public_inquiry' }, query: text,
      response_mode: 'blocking', conversation_id: conv_id, user: `public:${user_id}` })
  });
  const dify = await difyRes.json();
  const raw  = (dify.answer ?? '').trim();
  new_conv_id = dify.conversation_id ?? conv_id;
  const prefixMatch = raw.match(/^(AUTO|BOOKING_ASK|BOOKING_DONE|CONSULT|ESCALATE[^:]*):/i);
  route_prefix = prefixMatch ? prefixMatch[1].toUpperCase() : null;

  if      (/^AUTO:/i.test(raw))         answer = raw.replace(/^AUTO:\s*/i, '');
  else if (/^BOOKING_ASK:/i.test(raw))  answer = raw.replace(/^BOOKING_ASK:\s*/i, '');
  else if (/^BOOKING_DONE:/i.test(raw)) {
    let bookingData = {};
    try { bookingData = JSON.parse(raw.replace(/^BOOKING_DONE:\s*/i, '').trim()); } catch(e) {}
    if (!/^\d{1,2}\/\d{1,2}/.test(bookingData.date || '')) {
      answer = 'ขอวันที่เป็นตัวเลขด้วยนะคะ เช่น 21/6 หรือ 5/8 ค่ะ';
    } else {
    let request_uid = '';
    try {
      const bRes = await fetch(`${BRIDGE_URL}/internal/booking`, {
        method: 'POST', headers: AUTH_HDR,
        body: JSON.stringify({ user_id,
          name: bookingData.name || '', phone: bookingData.phone || '',
          email: bookingData.email || '',
          date: bookingData.date || '', time: bookingData.time || '',
          symptom: bookingData.symptom || '', raw_summary: bookingData })
      });
      if (bRes.ok) request_uid = (await bRes.json()).request_uid || '';
    } catch(e) { console.error('save booking error:', String(e?.message ?? e)); }
    if (request_uid) {
      try {
        const croUserRes = await fetch(`${BRIDGE_URL}/internal/booking/cro-user/latest`, { headers: AUTH_HDR });
        const cro_uid = croUserRes.ok ? (await croUserRes.json()).user_id : null;
        if (cro_uid) {
          const croTok = await getLineToken(
            $vars.LINE_CRO_CHANNEL_ID || process.env.LINE_CRO_CHANNEL_ID || '',
            $vars.LINE_CRO_CHANNEL_SECRET || process.env.LINE_CRO_CHANNEL_SECRET || ''
          );
          const summary = `มีการจองคิวใหม่\n- ชื่อ: ${bookingData.name||'-'}\n- เบอร์: ${bookingData.phone||'-'}\n- อีเมล: ${bookingData.email||'-'}\n- วัน: ${bookingData.date||'-'} เวลา ${bookingData.time||'-'}\n- อาการ: ${bookingData.symptom||'-'}`;
          await fetch('https://api.line.me/v2/bot/message/push', {
            method: 'POST',
            headers: { Authorization: `Bearer ${croTok}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ to: cro_uid, messages: [{ type: 'text', text: summary,
              quickReply: { items: [
                { type: 'action', action: { type: 'postback', label: 'ยืนยัน', data: `CONFIRM:${request_uid}` } },
                { type: 'action', action: { type: 'postback', label: 'ไม่รับ', data: `REJECT:${request_uid}` } }
              ]}}]})
          });
        }
      } catch(e) { console.error('push CRO error:', String(e?.message ?? e)); }
    }
    answer = 'รับทราบค่ะ รอเจ้าหน้าที่ยืนยันนัดหมายในไม่ช้าค่ะ';
    }
  }
  else if (/^CONSULT:/i.test(raw))       answer = raw.replace(/^CONSULT:\s*/i, '');
  else if (/^ESCALATE:emergency/i.test(raw)) answer = 'พบสัญญาณอันตราย โปรดโทร 1669 หรือไปโรงพยาบาลใกล้บ้านทันที';
  else if (/^ESCALATE/i.test(raw))      answer = 'ขอโทษค่ะ เรื่องนี้ต้องให้เจ้าหน้าที่ช่วยดูแลแทนค่ะ กรุณารอสักครู่ เจ้าหน้าที่จะติดต่อกลับ';
  else if (raw)                         answer = raw;
} catch (e) { console.error('Dify error:', String(e?.message ?? e)); }

// 3. save conv_id
if (new_conv_id) {
  try {
    await fetch(SESSION_URL, { method: 'POST', headers: AUTH_HDR,
      body: JSON.stringify({ dify_conversation_id: new_conv_id, current_state: 'active' }) });
  } catch (e) {}
}

// COPILOT branch: log AI draft, push to CRO for review — do NOT reply patient.
if (effective_mode === 'copilot') {
  try {
    await fetch(MESSAGE_URL, { method: 'POST', headers: AUTH_HDR,
      body: JSON.stringify({ external_user_id: user_id, direction: 'out',
        text: answer, route_prefix: (route_prefix ? `COPILOT_DRAFT:${route_prefix}` : 'COPILOT_DRAFT') }) });
  } catch(e) {}
  await pushCroAlert(`[Copilot draft] ผู้ใช้ ${user_id}\nคำถาม: ${text}\n\nAI ร่างไว้:\n${answer}\n\n(ยังไม่ส่ง เข้า BBH Portal เพื่อยืนยัน)`);
  return [{ json: { ok: true, user_id, mode: 'copilot', draft: answer, sent: false } }];
}

// 4. AUTO branch: log outbound + reply LINE
try {
  await fetch(MESSAGE_URL, { method: 'POST', headers: AUTH_HDR,
    body: JSON.stringify({ external_user_id: user_id, direction: 'out',
      text: answer, route_prefix }) });
} catch(e) {}
try {
  const token = await getLineToken(
    $vars.LINE_CHANNEL_ID || process.env.LINE_CHANNEL_ID || '',
    $vars.LINE_CHANNEL_SECRET || process.env.LINE_CHANNEL_SECRET || ''
  );
  await fetch('https://api.line.me/v2/bot/message/reply', {
    method: 'POST',
    headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ replyToken: reply_token, messages: [{ type: 'text', text: answer.slice(0, 5000) }] })
  });
} catch (e) { console.error('LINE reply error:', String(e?.message ?? e)); }

return [{ json: { ok: true, user_id, conv_id: new_conv_id, answer, mode: effective_mode } }];

