}const t = (text || '').trim();
const isConfirm = /^(ยืนยัน|confirm|ok|ตกลง|ใช่|รับ)/i.test(t);
const isReject  = /^(ไม่รับ|ปฏิเสธ|reject|cancel|ยกเลิก)/i.test(t);

if (!isConfirm && !isReject) return [];

const bRes = await fetch(`${BRIDGE_URL}/internal/booking/latest-pending`, { headers: AUTH_HDR });
if (!bRes.ok) return [];
const booking = await bRes.json();
if (!booking || !booking.request_uid) return [];

const action = isConfirm ? 'CONFIRM' : 'REJECT';
return [{ json: {
  event_type: 'postback',
  user_id,
  reply_token,
  text: `${action}:${booking.request_uid}`
}}];

const { user_id, reply_token, text: postback_data } = $json;
const BRIDGE_URL = $vars.BRIDGE_INTERNAL_URL || process.env.BRIDGE_INTERNAL_URL || 'http://hospital-bridge:8000';
const BRIDGE_TOK = $vars.BRIDGE_INTERNAL_TOKEN || process.env.BRIDGE_INTERNAL_TOKEN || '';
