  const r = await fetch('https://api.line.me/v2/oauth/accessToken', {
    method: 'POST', headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: `grant_type=client_credentials&client_id=${encodeURIComponent(id)}&client_secret=${encodeURIComponent(sec)}`
  });
  return (await r.json()).access_token;
}async function lineReply(tok, rt, msg) {
  if (!rt || rt === 'noreply') return;
  await fetch('https://api.line.me/v2/bot/message/reply', {
    method: 'POST',
    headers: { Authorization: `Bearer ${tok}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ replyToken: rt, messages: [{ type: 'text', text: msg.slice(0, 5000) }] })
  });
}

const match = (postback_data || '').match(/^(CONFIRM|REJECT):(.+)$/i);
if (!match) return [];
const [, action, request_uid] = match;

const croToken = await getLineToken(
  $vars.LINE_CRO_CHANNEL_ID || process.env.LINE_CRO_CHANNEL_ID || '',
  $vars.LINE_CRO_CHANNEL_SECRET || process.env.LINE_CRO_CHANNEL_SECRET || ''
);
const mainToken = await getLineToken(
  $vars.LINE_CHANNEL_ID || process.env.LINE_CHANNEL_ID || '',
  $vars.LINE_CHANNEL_SECRET || process.env.LINE_CHANNEL_SECRET || ''
);

const bookingRes = await fetch(`${BRIDGE_URL}/internal/booking/${request_uid}`, { headers: AUTH_HDR });
if (!bookingRes.ok) {
  await lineReply(croToken, reply_token, 'ไม่พบข้อมูลการจองค่ะ');
  return [];
}
const booking = await bookingRes.json();
const patient_uid = booking.external_user_id;

if (action.toUpperCase() === 'REJECT') {
  return [{ json: { action: 'reject', request_uid, patient_uid, user_id, reply_token, croToken, mainToken, booking } }];
}

// CONFIRM — parse date
const dt_text = booking.requested_datetime_text || '';
const dtMatch = dt_text.match(/(\d{1,2})\/(\d{1,2})(?:\/(\d{2,4}))?\s+(\d{1,2}):(\d{2})/);
if (!dtMatch) {
  await lineReply(croToken, reply_token, `ไม่สามารถอ่านวันที่ได้: "${dt_text}"\nกรุณาใช้รูปแบบ dd/mm HH:MM ค่ะ`);
  return [];
